  export async function seedNetworkData() {
    try {
      const hpCountRes = await db.execute(sql`SELECT COUNT(*) as cnt FROM hotspot_points`);
      const bpCountRes = await db.execute(sql`SELECT COUNT(*) as cnt FROM broadband_points`);
      const hpCount = Number((hpCountRes.rows[0] as any)?.cnt ?? 0);
      const bpCount = Number((bpCountRes.rows[0] as any)?.cnt ?? 0);

      if (hpCount === 0) {
        for (let i = 0; i < HOTSPOT_ROWS.length; i += 50) {
          await db.insert(hotspotPointsTable).values(HOTSPOT_ROWS.slice(i, i + 50));
        }
        logger.info({ count: HOTSPOT_ROWS.length }, "Seeded hotspot network points");
      } else {
        logger.info({ count: hpCount }, "Hotspot points already seeded, skipping");
      }

      if (bpCount === 0) {
        for (let i = 0; i < BROADBAND_ROWS.length; i += 50) {
          await db.insert(broadbandPointsTable).values(BROADBAND_ROWS.slice(i, i + 50));
        }
        logger.info({ count: BROADBAND_ROWS.length }, "Seeded broadband network points");
      } else {
        logger.info({ count: bpCount }, "Broadband points already seeded, skipping");
      }
    } catch (err) {
      logger.error({ err }, "Network data seed failed (non-fatal)");
    }
  }
  